  1	import React, { FC, useState } from 'react';
  2	import { useNavigate } from 'react-router-dom-v5-compat';
  3	
  4	import DataVolumeModel from '@kubevirt-ui/kubevirt-api/console/models/DataVolumeModel';
  5	import VirtualMachineModel, {
  6	  VirtualMachineModelRef,
  7	} from '@kubevirt-ui/kubevirt-api/console/models/VirtualMachineModel';
  8	import { V1beta1DataVolume } from '@kubevirt-ui/kubevirt-api/containerized-data-importer/models';
  9	import { IoK8sApiCoreV1PersistentVolumeClaim } from '@kubevirt-ui/kubevirt-api/kubernetes';
 10	import {
 11	  V1beta1VirtualMachineSnapshot,
 12	  V1VirtualMachine,
 13	} from '@kubevirt-ui/kubevirt-api/kubevirt';
 14	import ConfirmActionMessage from '@kubevirt-utils/components/ConfirmActionMessage/ConfirmActionMessage';
 15	import { GracePeriodInput } from '@kubevirt-utils/components/GracePeriodInput/GracePeriodInput';
 16	import TabModal from '@kubevirt-utils/components/TabModal/TabModal';
 17	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 18	import { useLastNamespacePath } from '@kubevirt-utils/hooks/useLastNamespacePath';
 19	import { buildOwnerReference } from '@kubevirt-utils/resources/shared';
 20	import { k8sDelete } from '@openshift-console/dynamic-plugin-sdk';
 21	import { ButtonVariant, Stack, StackItem } from '@patternfly/react-core';
 22	
 23	import DeleteOwnedResourcesMessage from './components/DeleteOwnedResourcesMessage';
 24	import useDeleteVMResources from './hooks/useDeleteVMResources';
 25	import {
 26	  deleteSecrets,
 27	  removeDataVolumeTemplatesToVM,
 28	  updateSnapshotResources,
 29	  updateVolumeResources,
 30	} from './utils/helpers';
 31	import { DEFAULT_GRACE_PERIOD } from './constants';
 32	
 33	type DeleteVMModalProps = {
 34	  isOpen: boolean;
 35	  onClose: () => void;
 36	  vm: V1VirtualMachine;
 37	};
 38	
 39	const DeleteVMModal: FC<DeleteVMModalProps> = ({ isOpen, onClose, vm }) => {
 40	  const { t } = useKubevirtTranslation();
 41	  const navigate = useNavigate();
 42	  const [gracePeriodCheckbox, setGracePeriodCheckbox] = useState<boolean>(false);
 43	  const [gracePeriodSeconds, setGracePeriodSeconds] = useState<number>(
 44	    vm?.spec?.template?.spec?.terminationGracePeriodSeconds || DEFAULT_GRACE_PERIOD,
 45	  );
 46	
 47	  const [volumesToSave, setVolumesToSave] = useState<
 48	    (IoK8sApiCoreV1PersistentVolumeClaim | V1beta1DataVolume)[]
 49	  >([]);
 50	
 51	  const [snapshotsToSave, setSnapshotsToSave] = useState<V1beta1VirtualMachineSnapshot[]>([]);
 52	
 53	  const { dataVolumes, loaded, pvcs, secrets, snapshots } = useDeleteVMResources(vm);
 54	  const lastNamespacePath = useLastNamespacePath();
 55	
 56	  const onDelete = async (updatedVM: V1VirtualMachine) => {
 57	    const vmOwnerRef = buildOwnerReference(updatedVM);
 58	
 59	    await removeDataVolumeTemplatesToVM(
 60	      vm,
 61	      volumesToSave.filter((volume) => volume.kind === DataVolumeModel.kind) as V1beta1DataVolume[],
 62	    );
 63	
 64	    await Promise.allSettled(updateVolumeResources(volumesToSave, vmOwnerRef));
 65	
 66	    await Promise.allSettled(updateSnapshotResources(snapshotsToSave, vmOwnerRef));
 67	
 68	    await Promise.allSettled(deleteSecrets(secrets));
 69	
 70	    await k8sDelete({
 71	      json: gracePeriodCheckbox
 72	        ? { apiVersion: 'v1', gracePeriodSeconds, kind: 'DeleteOptions' }
 73	        : null,
 74	      model: VirtualMachineModel,
 75	      resource: updatedVM,
 76	    });
 77	    navigate(`/k8s/${lastNamespacePath}/${VirtualMachineModelRef}`);
 78	  };
 79	
 80	  return (
 81	    <TabModal<V1VirtualMachine>
 82	      headerText={t('Delete VirtualMachine?')}
 83	      isOpen={isOpen}
 84	      obj={vm}
 85	      onClose={onClose}
 86	      onSubmit={onDelete}
 87	      submitBtnText={t('Delete')}
 88	      submitBtnVariant={ButtonVariant.danger}
 89	    >
 90	      <Stack hasGutter>
 91	        <StackItem>
 92	          <ConfirmActionMessage obj={vm} />
 93	        </StackItem>
 94	        <GracePeriodInput
 95	          gracePeriodSeconds={gracePeriodSeconds}
 96	          isChecked={gracePeriodCheckbox}
 97	          onCheckboxChange={setGracePeriodCheckbox}
 98	          setGracePeriodSeconds={setGracePeriodSeconds}
 99	        />
100	        <DeleteOwnedResourcesMessage
101	          dataVolumes={dataVolumes}
102	          loaded={loaded}
103	          pvcs={pvcs}
104	          setSnapshotsToSave={setSnapshotsToSave}
105	          setVolumesToSave={setVolumesToSave}
106	          snapshots={snapshots}
107	          snapshotsToSave={snapshotsToSave}
108	          volumesToSave={volumesToSave}
109	        />
110	      </Stack>
111	    </TabModal>
112	  );
113	};
114	
115	export default DeleteVMModal;

